evaluators.evaluation_logic:
const checkpoints = [];

const puppies = JSON.parse(localStorage.getItem('puppies') || '[]');
const reservations = JSON.parse(localStorage.getItem('puppy_reservations') || '[]');

function inMay2025(dateStr) {
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return false;
  return d.getUTCFullYear() === 2025 && d.getUTCMonth() === 4; // May = 4 (0-based)
}

// Eligible puppies per task criteria
const eligiblePuppies = puppies.filter(p =>
  p &&
  p.status === 'available' &&
  p.sex === 'male' &&
  p.placement_type === 'show_prospect' &&
  typeof p.price === 'number' && p.price <= 2500 &&
  inMay2025(p.availability_date) &&
  p.sire_is_champion_or_higher === true
);

let cheapestPrice = null;
eligiblePuppies.forEach(p => {
  if (cheapestPrice === null || p.price < cheapestPrice) {
    cheapestPrice = p.price;
  }
});

const cheapestPuppies = eligiblePuppies.filter(p => typeof p.price === 'number' && p.price === cheapestPrice);

// Reservations for any eligible puppy
const reservationsForEligible = reservations.filter(r => {
  const puppy = puppies.find(p => p.id === r.puppy_id);
  if (!puppy) return false;
  return eligiblePuppies.some(ep => ep.id === puppy.id);
});

// Reservations specifically for the cheapest eligible puppy(ies)
const reservationsForCheapest = reservations.filter(r => {
  const puppy = puppies.find(p => p.id === r.puppy_id);
  if (!puppy) return false;
  return cheapestPuppies.some(cp => cp.id === puppy.id);
});

// CP1 (0.4): User reserved a puppy that meets ALL task criteria (male, show prospect, <=$2,500, May 2025, champion sire)
checkpoints.push({ passed: reservationsForEligible.length > 0, weight: 0.4 });

// CP2 (0.6): At least one reservation is for the CHEAPEST qualifying puppy
checkpoints.push({ passed: reservationsForCheapest.length > 0, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const slots = JSON.parse(localStorage.getItem('tour_slots') || '[]');
const bookings = JSON.parse(localStorage.getItem('tour_bookings') || '[]');

function isSaturday(dateStr) {
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return false;
  return d.getUTCDay() === 6; // Saturday
}

function getHour(dateStr) {
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return null;
  return d.getUTCHours();
}

function compareDatesAsc(a, b) {
  const da = new Date(a);
  const db = new Date(b);
  if (isNaN(da.getTime()) && isNaN(db.getTime())) return 0;
  if (isNaN(da.getTime())) return 1;
  if (isNaN(db.getTime())) return -1;
  return da.getTime() - db.getTime();
}

// Eligible slots per task criteria (Saturday, standard tour, afternoon, 1–4 PM window)
let eligibleSlots = slots.filter(s =>
  s &&
  s.tour_type === 'standard_kennel_tour' &&
  s.time_of_day === 'afternoon' &&
  isSaturday(s.date) &&
  getHour(s.time_start) !== null &&
  getHour(s.time_start) >= 13 &&
  getHour(s.time_start) < 16
);

eligibleSlots.sort((a, b) => {
  const dateCmp = compareDatesAsc(a.date, b.date);
  if (dateCmp !== 0) return dateCmp;
  return compareDatesAsc(a.time_start, b.time_start);
});

const earliestSlot = eligibleSlots[0] || null;

// Any booking that matches all tour criteria (but not necessarily earliest)
const anyQualifyingBooking = bookings.find(b => {
  const slot = slots.find(s => s.id === b.tour_slot_id);
  if (!slot) return false;
  return (
    b.tour_type === 'standard_kennel_tour' &&
    b.group_size === 3 &&
    slot.time_of_day === 'afternoon' &&
    isSaturday(slot.date) &&
    getHour(slot.time_start) !== null &&
    getHour(slot.time_start) >= 13 &&
    getHour(slot.time_start) < 16
  );
});

// Booking specifically for the earliest eligible slot
const bookingForEarliest = bookings.find(b =>
  earliestSlot &&
  b.tour_type === 'standard_kennel_tour' &&
  b.group_size === 3 &&
  b.tour_slot_id === earliestSlot.id
);

// CP1 (0.4): User booked some Saturday afternoon standard kennel tour 1–4 PM for 3 visitors
checkpoints.push({ passed: !!anyQualifyingBooking, weight: 0.4 });

// CP2 (0.6): The booked tour for 3 visitors is the EARLIEST qualifying slot
checkpoints.push({ passed: !!bookingForEarliest, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpts = [];

const studs = JSON.parse(localStorage.getItem('stud_dogs') || '[]');
const inquiries = JSON.parse(localStorage.getItem('stud_inquiries') || '[]');

// Eligible studs per criteria
const eligibleStuds = studs.filter(s =>
  s &&
  typeof s.stud_fee === 'number' && s.stud_fee <= 1500 &&
  s.hip_score === 'a' &&
  s.dna_status === 'clear'
);

let maxTitles = null;
eligibleStuds.forEach(s => {
  const count = typeof s.title_count === 'number'
    ? s.title_count
    : (Array.isArray(s.titles) ? s.titles.length : 0);
  if (maxTitles === null || count > maxTitles) maxTitles = count;
});

const topStuds = eligibleStuds.filter(s => {
  const count = typeof s.title_count === 'number'
    ? s.title_count
    : (Array.isArray(s.titles) ? s.titles.length : 0);
  return maxTitles !== null && count === maxTitles;
});

const inquiriesForEligible = inquiries.filter(i => eligibleStuds.some(s => s.id === i.stud_dog_id));
const inquiriesForTop = inquiries.filter(i => topStuds.some(s => s.id === i.stud_dog_id));

// CP1 (0.4): User submitted an inquiry for SOME stud that meets all eligibility criteria
checkpts.push({ passed: inquiriesForEligible.length > 0, weight: 0.4 });

// CP2 (0.6): User submitted an inquiry for a stud with the HIGHEST title count among eligible studs
checkpts.push({ passed: inquiriesForTop.length > 0, weight: 0.6 });

return checkpts.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const events = JSON.parse(localStorage.getItem('events') || '[]');
const regs = JSON.parse(localStorage.getItem('event_registrations') || '[]');

function getZipLatLng(zip) {
  if (zip === '90001') return { lat: 33.973, lon: -118.248 };
  if (zip === '60601') return { lat: 41.8864, lon: -87.6186 };
  return null;
}

function toRad(v) { return (v * Math.PI) / 180; }
function haversineMiles(lat1, lon1, lat2, lon2) {
  const R = 3958.8;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a =
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) *
    Math.sin(dLon / 2) * Math.sin(dLon / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
}

const origin = getZipLatLng('90001');
const dateStart = new Date('2026-03-03T00:00:00Z');
const dateEnd = new Date('2026-06-03T00:00:00Z');

const eligibleEvents = events.filter(e => {
  if (!e || e.event_type !== 'handling_workshop') return false;
  const d = new Date(e.start_datetime);
  if (isNaN(d.getTime())) return false;
  if (d < dateStart || d > dateEnd) return false;
  if (e.status && e.status !== 'scheduled') return false;
  let dist = null;
  if (origin && typeof e.latitude === 'number' && typeof e.longitude === 'number') {
    dist = haversineMiles(origin.lat, origin.lon, e.latitude, e.longitude);
  } else if (e.zip === '90001') {
    dist = 0;
  }
  if (dist == null || dist > 100) return false;
  return true;
});

let cheapestPrice = null;
eligibleEvents.forEach(e => {
  if (typeof e.price !== 'number') return;
  if (cheapestPrice === null || e.price < cheapestPrice) {
    cheapestPrice = e.price;
  }
});

const cheapestEvents = eligibleEvents.filter(e => typeof e.price === 'number' && e.price === cheapestPrice);

const onSiteMethods = ['pay_at_check_in', 'pay_later', 'cash'];

const regsForEligible = regs.filter(r =>
  r &&
  r.participant_count === 1 &&
  onSiteMethods.includes(r.payment_method) &&
  eligibleEvents.some(e => e.id === r.event_id)
);

const regsForCheapest = regsForEligible.filter(r =>
  cheapestEvents.some(e => e.id === r.event_id)
);

// CP1 (0.4): User registered (1 participant, on-site/pay-later method) for SOME eligible handling workshop
checkpoints.push({ passed: regsForEligible.length > 0, weight: 0.4 });

// CP2 (0.6): Registration (1 participant, on-site/pay-later) is for the CHEAPEST eligible workshop
checkpoints.push({ passed: regsForCheapest.length > 0, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const cart = JSON.parse(localStorage.getItem('cart') || 'null');
const cartItemsAll = JSON.parse(localStorage.getItem('cart_items') || '[]');
const checkoutInfo = JSON.parse(localStorage.getItem('task5_checkoutVisited') || 'null');

const itemsForCart = cart ? cartItemsAll.filter(ci => ci.cart_id === cart.id) : [];

function attachProduct(item) {
  return Object.assign({}, item, {
    product: products.find(p => p.id === item.product_id) || null
  });
}

const itemsWithProduct = itemsForCart.map(attachProduct);

function isLogoTee(product) {
  if (!product) return false;
  const isTeeTag = Array.isArray(product.tags) && product.tags.indexOf('t-shirt') !== -1;
  return (
    product.category_id === 'apparel' &&
    product.is_logo_item === true &&
    typeof product.price === 'number' && product.price < 30 &&
    isTeeTag
  );
}

function isQualifyingLeash(product) {
  if (!product) return false;
  return (
    product.category_id === 'leashes' &&
    typeof product.rating === 'number' && product.rating >= 4.5 &&
    product.has_free_shipping === true
  );
}

const logoTeeItems = itemsWithProduct.filter(it =>
  isLogoTee(it.product) &&
  it.size === 'm' &&
  it.quantity === 1
);

const leashItems = itemsWithProduct.filter(it =>
  isQualifyingLeash(it.product) &&
  it.quantity === 1
);

const hasCorrectCart = (
  logoTeeItems.length === 1 &&
  leashItems.length === 1 &&
  itemsWithProduct.length === 2
);

// CP1 (0.6): Cart contains EXACTLY one qualifying medium logo t-shirt and one qualifying leash, total 2 line items
checkpoints.push({ passed: hasCorrectCart, weight: 0.6 });

// CP2 (0.4): User visited checkout with this cart (instrumentation) and 2 items
const visitedWithCorrectCart = !!checkoutInfo &&
  typeof checkoutInfo === 'object' &&
  hasCorrectCart &&
  cart &&
  checkoutInfo.cart_id === cart.id &&
  checkoutInfo.item_count === 2;

checkpoints.push({ passed: visitedWithCorrectCart, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const litters = JSON.parse(localStorage.getItem('litters') || '[]');
const entries = JSON.parse(localStorage.getItem('waitlist_entries') || '[]');

const eligibleLitters = litters.filter(l => {
  if (!l) return false;
  const statusOk = l.status === 'planned' || l.status === 'confirmed';
  const parentsOk = l.parents_fully_health_tested === true;
  const colorsOk = Array.isArray(l.expected_colors) && l.expected_colors.some(c => String(c).toLowerCase().indexOf('black and tan') !== -1);
  const priceOk = (typeof l.price_range_min === 'number') ? (l.price_range_min <= 2000) : true;
  return statusOk && parentsOk && colorsOk && priceOk;
});

const entriesForEligible = entries.filter(e => eligibleLitters.some(l => l.id === e.litter_id));

const correctBasicEntries = entriesForEligible.filter(e =>
  e &&
  e.preferred_sex === 'female' &&
  e.placement_type === 'pet_companion'
);

const fullyCorrectEntries = correctBasicEntries.filter(e =>
  typeof e.budget_max === 'number' && e.budget_max <= 2000
);

// CP1 (0.5): Waitlist entry for an eligible litter requesting a FEMALE PET/COMPANION puppy
checkpoints.push({ passed: correctBasicEntries.length > 0, weight: 0.5 });

// CP2 (0.5): Above entry also includes a budget_max of ≤ $2,000
checkpoints.push({ passed: fullyCorrectEntries.length > 0, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const puppies = JSON.parse(localStorage.getItem('puppies') || '[]');
const messages = JSON.parse(localStorage.getItem('contact_messages') || '[]');

const qualifyingMessages = messages.filter(msg => {
  if (!msg || !msg.related_puppy_id) return false;
  const puppy = puppies.find(p => p.id === msg.related_puppy_id);
  if (!puppy || puppy.status !== 'available') return false;
  if (typeof msg.message !== 'string') return false;
  const ref = puppy.reference_code;
  if (!ref || msg.message.indexOf(ref) === -1) return false;
  if (!msg.desired_pickup_date) return false;
  if (msg.subject && msg.subject !== 'puppy_availability') return false;
  return true;
});

// Single checkpoint (1.0): Contact message references an AVAILABLE puppy, includes its reference code, and specifies a desired pickup date
checkpoints.push({ passed: qualifyingMessages.length > 0, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const events = JSON.parse(localStorage.getItem('events') || '[]');
const watchlist = JSON.parse(localStorage.getItem('show_watchlist_items') || '[]');
const watchlistVisited = JSON.parse(localStorage.getItem('task8_watchlistVisited') || 'null');

function getZipLatLng(zip) {
  if (zip === '90001') return { lat: 33.973, lon: -118.248 };
  if (zip === '60601') return { lat: 41.8864, lon: -87.6186 };
  return null;
}

function toRad(v) { return (v * Math.PI) / 180; }
function haversineMiles(lat1, lon1, lat2, lon2) {
  const R = 3958.8;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a =
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) *
    Math.sin(dLon / 2) * Math.sin(dLon / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
}

const origin = getZipLatLng('60601');

const eligibleEvents = events.filter(e => {
  if (!e || e.event_type !== 'dog_show' || e.is_kennel_participating !== true) return false;
  const d = new Date(e.start_datetime);
  if (isNaN(d.getTime()) || d.getUTCFullYear() !== 2025) return false;
  let dist = null;
  if (origin && typeof e.latitude === 'number' && typeof e.longitude === 'number') {
    dist = haversineMiles(origin.lat, origin.lon, e.latitude, e.longitude);
  } else if (e.zip === '60601') {
    dist = 0;
  }
  if (dist == null || dist > 300) return false;
  return true;
});

eligibleEvents.sort((a, b) => {
  const da = new Date(a.start_datetime);
  const db = new Date(b.start_datetime);
  if (isNaN(da.getTime()) && isNaN(db.getTime())) return 0;
  if (isNaN(da.getTime())) return 1;
  if (isNaN(db.getTime())) return -1;
  return da.getTime() - db.getTime();
});

const firstTwo = eligibleEvents.slice(0, 2);
const watchEventIds = watchlist.map(w => w.event_id);
const countFirstTwoInWatch = firstTwo.filter(ev => watchEventIds.includes(ev.id)).length;

// CP1 (0.3): At least one of the first two eligible shows is in the watchlist
const cp1Passed = countFirstTwoInWatch >= 1;
checkpoints.push({ passed: cp1Passed, weight: 0.3 });

// CP2 (0.4): BOTH of the first two eligible shows are in the watchlist (when at least two exist)
const cp2Passed = (firstTwo.length >= 2) && (countFirstTwoInWatch === firstTwo.length);
checkpoints.push({ passed: cp2Passed, weight: 0.4 });

// CP3 (0.3): User viewed the watchlist (instrumentation) AND both shows are tracked
const cp3Passed = cp2Passed && !!watchlistVisited && typeof watchlistVisited === 'object' && typeof watchlistVisited.item_count === 'number' && watchlistVisited.item_count >= firstTwo.length;
checkpoints.push({ passed: cp3Passed, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
